"""
Parameterized generator for GH209_core_119328.

Source PR:    https://github.com/home-assistant/core/pull/119328
Source Issue: https://github.com/home-assistant/core/issues/111380

Seed varies: renames 'add_to_hass' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH209_core_119328'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH209_core_119328'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('add_to_hass', 'add_to_hass' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH209_core_119328',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'home-assistant/core',
                "pr_number": 119328,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/home-assistant/core/pull/119328",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'homeassistant/components/utility_meter/__init__.py': '"""Support for tracking consumption over given periods of time."""\n\nfrom datetime import timedelta\nimport logging\n\nfrom croniter import croniter\nimport voluptuous as vol\n\nfrom homeassistant.components.select import DOMAIN as SELECT_DOMAIN\nfrom homeassistant.components.sensor import DOMAIN as SENSOR_DOMAIN\nfrom homeassistant.config_entries import ConfigEntry\nfrom homeassistant.const import ATTR_ENTITY_ID, CONF_NAME, CONF_UNIQUE_ID, Platform\nfrom homeassistant.core import HomeAssistant, split_entity_id\nfrom homeassistant.helpers import (\n    device_registry as dr,\n    discovery,\n    entity_registry as er,\n)\nimport homeassistant.helpers.config_validation as cv\nfrom homeassistant.helpers.dispatcher import async_dispatcher_send\nfrom homeassistant.helpers.typing import ConfigType\n\nfrom .const import (\n    CONF_CRON_PATTERN,\n    CONF_METER,\n    CONF_METER_DELTA_VALUES,\n    CONF_METER_NET_CONSUMPTION,\n    CONF_METER_OFFSET,\n    CONF_METER_PERIODICALLY_RESETTING,\n    CONF_METER_TYPE,\n    CONF_SENSOR_ALWAYS_AVAILABLE,\n    CONF_SOURCE_SENSOR,\n    CONF_TARIFF,\n    CONF_TARIFF_ENTITY,\n    CONF_TARIFFS,\n    DATA_TARIFF_SENSORS,\n    DATA_UTILITY,\n    DOMAIN,\n    METER_TYPES,\n    SERVICE_RESET,\n    SIGNAL_RESET_METER,\n)\n\n_LOGGER = logging.getLogger(__name__)\n\nDEFAULT_OFFSET = timedelta(hours=0)\n\n\ndef validate_cron_pattern(pattern):\n    """Check that the pattern is well-formed."""\n    if croniter.is_valid(pattern):\n        return pattern\n    raise vol.Invalid("Invalid pattern")\n\n\ndef period_or_cron(config):\n    """Check that if cron pattern is used, then meter type and offsite must be removed."""\n    if CONF_CRON_PATTERN in config and CONF_METER_TYPE in config:\n        raise vol.Invalid(f"Use <{CONF_CRON_PATTERN}> or <{CONF_METER_TYPE}>")\n    if (\n        CONF_CRON_PATTERN in config\n        and CONF_METER_OFFSET in config\n        and config[CONF_METER_OFFSET] != DEFAULT_OFFSET\n    ):\n        raise vol.Invalid(\n            f"When <{CONF_CRON_PATTERN}> is used <{CONF_METER_OFFSET}> has no meaning"\n        )\n    return config\n\n\ndef max_28_days(config):\n    """Check that time period does not include more than 28 days."""\n    if config.days >= 28:\n        raise vol.Invalid(\n            "Unsupported offset of more than 28 days, please use a cron pattern."\n        )\n\n    return config\n\n\nMETER_CONFIG_SCHEMA = vol.Schema(\n    vol.All(\n        {\n            vol.Required(CONF_SOURCE_SENSOR): cv.entity_id,\n            vol.Optional(CONF_NAME): cv.string,\n            vol.Optional(CONF_UNIQUE_ID): cv.string,\n            vol.Optional(CONF_METER_TYPE): vol.In(METER_TYPES),\n            vol.Optional(CONF_METER_OFFSET, default=DEFAULT_OFFSET): vol.All(\n                cv.time_period, cv.positive_timedelta, max_28_days\n            ),\n            vol.Optional(CONF_METER_DELTA_VALUES, default=False): cv.boolean,\n            vol.Optional(CONF_METER_NET_CONSUMPTION, default=False): cv.boolean,\n            vol.Optional(CONF_METER_PERIODICALLY_RESETTING, default=True): cv.boolean,\n            vol.Optional(CONF_TARIFFS, default=[]): vol.All(\n                cv.ensure_list, vol.Unique(), [cv.string]\n            ),\n            vol.Optional(CONF_CRON_PATTERN): validate_cron_pattern,\n            vol.Optional(CONF_SENSOR_ALWAYS_AVAILABLE, default=False): cv.boolean,\n        },\n        period_or_cron,\n    )\n)\n\nCONFIG_SCHEMA = vol.Schema(\n    {DOMAIN: vol.Schema({cv.slug: METER_CONFIG_SCHEMA})}, extra=vol.ALLOW_EXTRA\n)\n\n\nasync def async_setup(hass: HomeAssistant, config: ConfigType) -> bool:\n    """Set up an Utility Meter."""\n    hass.data[DATA_UTILITY] = {}\n\n    async def async_reset_meters(service_call):\n        """Reset all sensors of a meter."""\n        meters = service_call.data["entity_id"]\n\n        for meter in meters:\n            _LOGGER.debug("resetting meter %s", meter)\n            domain, entity = split_entity_id(meter)\n            # backward compatibility up to 2022.07:\n            if domain == DOMAIN:\n                async_dispatcher_send(\n                    hass, SIGNAL_RESET_METER, f"{SELECT_DOMAIN}.{entity}"\n                )\n            else:\n                async_dispatcher_send(hass, SIGNAL_RESET_METER, meter)\n\n    hass.services.async_register(\n        DOMAIN,\n        SERVICE_RESET,\n        async_reset_meters,\n        vol.Schema({ATTR_ENTITY_ID: vol.All(cv.ensure_list, [cv.entity_id])}),\n    )\n\n    if DOMAIN not in config:\n        return True\n\n    for meter, conf in config[DOMAIN].items():\n        _LOGGER.debug("Setup %s.%s", DOMAIN, meter)\n\n        hass.data[DATA_UTILITY][meter] = conf\n        hass.data[DATA_UTILITY][meter][DATA_TARIFF_SENSORS] = []\n\n        if not conf[CONF_TARIFFS]:\n            # only one entity is required\n            hass.async_create_task(\n                discovery.async_load_platform(\n                    hass,\n                    SENSOR_DOMAIN,\n                    DOMAIN,\n                    {meter: {CONF_METER: meter}},\n                    config,\n                ),\n                eager_start=True,\n            )\n        else:\n            # create tariff selection\n            hass.async_create_task(\n                discovery.async_load_platform(\n                    hass,\n                    SELECT_DOMAIN,\n                    DOMAIN,\n                    {CONF_METER: meter, CONF_TARIFFS: conf[CONF_TARIFFS]},\n                    config,\n                ),\n                eager_start=True,\n            )\n\n            hass.data[DATA_UTILITY][meter][CONF_TARIFF_ENTITY] = (\n                f"{SELECT_DOMAIN}.{meter}"\n            )\n\n            # add one meter for each tariff\n            tariff_confs = {}\n            for tariff in conf[CONF_TARIFFS]:\n                name = f"{meter} {tariff}"\n                tariff_confs[name] = {\n                    CONF_METER: meter,\n                    CONF_TARIFF: tariff,\n                }\n\n            hass.async_create_task(\n                discovery.async_load_platform(\n                    hass, SENSOR_DOMAIN, DOMAIN, tariff_confs, config\n                ),\n                eager_start=True,\n            )\n\n    return True\n\n\nasync def async_setup_entry(hass: HomeAssistant, entry: ConfigEntry) -> bool:\n    """Set up Utility Meter from a config entry."""\n    entity_registry = er.async_get(hass)\n    hass.data[DATA_UTILITY][entry.entry_id] = {\n        "source": entry.options[CONF_SOURCE_SENSOR],\n    }\n    hass.data[DATA_UTILITY][entry.entry_id][DATA_TARIFF_SENSORS] = []\n\n    try:\n        er.async_validate_entity_id(entity_registry, entry.options[CONF_SOURCE_SENSOR])\n    except vol.Invalid:\n        # The entity is identified by an unknown entity registry ID\n        _LOGGER.error(\n            "Failed to setup utility_meter for unknown entity %s",\n            entry.options[CONF_SOURCE_SENSOR],\n        )\n        return False\n\n    if not entry.options.get(CONF_TARIFFS):\n        # Only a single meter sensor is required\n        hass.data[DATA_UTILITY][entry.entry_id][CONF_TARIFF_ENTITY] = None\n        await hass.config_entries.async_forward_entry_setups(entry, (Platform.SENSOR,))\n    else:\n        # Create tariff selection + one meter sensor for each tariff\n        entity_entry = entity_registry.async_get_or_create(\n            Platform.SELECT, DOMAIN, entry.entry_id, suggested_object_id=entry.title\n        )\n        hass.data[DATA_UTILITY][entry.entry_id][CONF_TARIFF_ENTITY] = (\n            entity_entry.entity_id\n        )\n        await hass.config_entries.async_forward_entry_setups(\n            entry, (Platform.SELECT, Platform.SENSOR)\n        )\n\n    entry.async_on_unload(entry.add_update_listener(config_entry_update_listener))\n\n    return True\n\n\nasync def config_entry_update_listener(hass: HomeAssistant, entry: ConfigEntry) -> None:\n    """Update listener, called when the config entry options are changed."""\n    old_source = hass.data[DATA_UTILITY][entry.entry_id]["source"]\n    await hass.config_entries.async_reload(entry.entry_id)\n\n    if old_source == entry.options[CONF_SOURCE_SENSOR]:\n        return\n\n    entity_registry = er.async_get(hass)\n    device_registry = dr.async_get(hass)\n\n    old_source_entity = entity_registry.async_get(old_source)\n    if not old_source_entity or not old_source_entity.device_id:\n        return\n\n    device_registry.async_update_device(\n        old_source_entity.device_id, remove_config_entry_id=entry.entry_id\n    )\n\n\nasync def async_unload_entry(hass: HomeAssistant, entry: ConfigEntry) -> bool:\n    """Unload a config entry."""\n    platforms_to_unload = [Platform.SENSOR]\n    if entry.options.get(CONF_TARIFFS):\n        platforms_to_unload.append(Platform.SELECT)\n\n    if unload_ok := await hass.config_entries.async_unload_platforms(\n        entry,\n        platforms_to_unload,\n    ):\n        hass.data[DATA_UTILITY].pop(entry.entry_id)\n\n    return unload_ok\n\n\nasync def async_migrate_entry(hass: HomeAssistant, config_entry: ConfigEntry) -> bool:\n    """Migrate old entry."""\n    _LOGGER.debug("Migrating from version %s", config_entry.version)\n\n    if config_entry.version == 1:\n        new = {**config_entry.options}\n        new[CONF_METER_PERIODICALLY_RESETTING] = True\n        hass.config_entries.async_update_entry(config_entry, options=new, version=2)\n\n    _LOGGER.info("Migration to version %s successful", config_entry.version)\n\n    return True\n',
            'tests/components/utility_meter/test_init.py': '"""The tests for the utility_meter component."""\n\nfrom __future__ import annotations\n\nfrom datetime import timedelta\n\nfrom freezegun import freeze_time\nimport pytest\n\nfrom homeassistant.components.select import (\n    ATTR_OPTION,\n    DOMAIN as SELECT_DOMAIN,\n    SERVICE_SELECT_OPTION,\n)\nfrom homeassistant.components.utility_meter.const import DOMAIN, SERVICE_RESET\nimport homeassistant.components.utility_meter.select as um_select\nimport homeassistant.components.utility_meter.sensor as um_sensor\nfrom homeassistant.const import (\n    ATTR_ENTITY_ID,\n    ATTR_UNIT_OF_MEASUREMENT,\n    CONF_PLATFORM,\n    EVENT_HOMEASSISTANT_START,\n    Platform,\n    UnitOfEnergy,\n)\nfrom homeassistant.core import HomeAssistant, State\nfrom homeassistant.helpers import entity_registry as er\nfrom homeassistant.setup import async_setup_component\nimport homeassistant.util.dt as dt_util\n\nfrom tests.common import MockConfigEntry, mock_restore_cache\n\n\nasync def test_restore_state(hass: HomeAssistant) -> None:\n    """Test utility sensor restore state."""\n    config = {\n        "utility_meter": {\n            "energy_bill": {\n                "source": "sensor.energy",\n                "tariffs": ["onpeak", "midpeak", "offpeak"],\n            }\n        }\n    }\n    mock_restore_cache(\n        hass,\n        [\n            State(\n                "select.energy_bill",\n                "midpeak",\n            ),\n        ],\n    )\n\n    assert await async_setup_component(hass, DOMAIN, config)\n    assert await async_setup_component(hass, Platform.SENSOR, config)\n    await hass.async_block_till_done()\n\n    # restore from cache\n    state = hass.states.get("select.energy_bill")\n    assert state.state == "midpeak"\n\n\n@pytest.mark.parametrize(\n    "meter",\n    [\n        ["select.energy_bill"],\n        "select.energy_bill",\n    ],\n)\nasync def test_services(hass: HomeAssistant, meter) -> None:\n    """Test energy sensor reset service."""\n    config = {\n        "utility_meter": {\n            "energy_bill": {\n                "source": "sensor.energy",\n                "cycle": "hourly",\n                "tariffs": ["peak", "offpeak"],\n            },\n            "energy_bill2": {\n                "source": "sensor.energy",\n                "cycle": "hourly",\n                "tariffs": ["peak", "offpeak"],\n            },\n        }\n    }\n\n    assert await async_setup_component(hass, DOMAIN, config)\n    assert await async_setup_component(hass, Platform.SENSOR, config)\n    await hass.async_block_till_done()\n\n    hass.bus.async_fire(EVENT_HOMEASSISTANT_START)\n    entity_id = config[DOMAIN]["energy_bill"]["source"]\n    hass.states.async_set(\n        entity_id, 1, {ATTR_UNIT_OF_MEASUREMENT: UnitOfEnergy.KILO_WATT_HOUR}\n    )\n    await hass.async_block_till_done()\n\n    now = dt_util.utcnow() + timedelta(seconds=10)\n    with freeze_time(now):\n        hass.states.async_set(\n            entity_id,\n            3,\n            {ATTR_UNIT_OF_MEASUREMENT: UnitOfEnergy.KILO_WATT_HOUR},\n            force_update=True,\n        )\n        await hass.async_block_till_done()\n\n    state = hass.states.get("sensor.energy_bill_peak")\n    assert state.state == "2"\n\n    state = hass.states.get("sensor.energy_bill_offpeak")\n    assert state.state == "0"\n\n    # Change tariff\n    data = {ATTR_ENTITY_ID: "select.energy_bill", ATTR_OPTION: "offpeak"}\n    await hass.services.async_call(SELECT_DOMAIN, SERVICE_SELECT_OPTION, data)\n    await hass.async_block_till_done()\n\n    now += timedelta(seconds=10)\n    with freeze_time(now):\n        hass.states.async_set(\n            entity_id,\n            4,\n            {ATTR_UNIT_OF_MEASUREMENT: UnitOfEnergy.KILO_WATT_HOUR},\n            force_update=True,\n        )\n        await hass.async_block_till_done()\n\n    state = hass.states.get("sensor.energy_bill_peak")\n    assert state.state == "2"\n\n    state = hass.states.get("sensor.energy_bill_offpeak")\n    assert state.state == "1"\n\n    # Change tariff\n    data = {ATTR_ENTITY_ID: "select.energy_bill", "option": "wrong_tariff"}\n    await hass.services.async_call(SELECT_DOMAIN, SERVICE_SELECT_OPTION, data)\n    await hass.async_block_till_done()\n\n    # Inexisting tariff, ignoring\n    assert hass.states.get("select.energy_bill").state != "wrong_tariff"\n\n    data = {ATTR_ENTITY_ID: "select.energy_bill", "option": "peak"}\n    await hass.services.async_call(SELECT_DOMAIN, SERVICE_SELECT_OPTION, data)\n    await hass.async_block_till_done()\n\n    now += timedelta(seconds=10)\n    with freeze_time(now):\n        hass.states.async_set(\n            entity_id,\n            5,\n            {ATTR_UNIT_OF_MEASUREMENT: UnitOfEnergy.KILO_WATT_HOUR},\n            force_update=True,\n        )\n        await hass.async_block_till_done()\n\n    state = hass.states.get("sensor.energy_bill_peak")\n    assert state.state == "3"\n\n    state = hass.states.get("sensor.energy_bill_offpeak")\n    assert state.state == "1"\n\n    # Reset meters\n    data = {ATTR_ENTITY_ID: meter}\n    await hass.services.async_call(DOMAIN, SERVICE_RESET, data)\n    await hass.async_block_till_done()\n\n    state = hass.states.get("sensor.energy_bill_peak")\n    assert state.state == "0"\n\n    state = hass.states.get("sensor.energy_bill_offpeak")\n    assert state.state == "0"\n\n    # meanwhile energy_bill2_peak accumulated all kWh\n    state = hass.states.get("sensor.energy_bill2_peak")\n    assert state.state == "4"\n\n\nasync def test_services_config_entry(hass: HomeAssistant) -> None:\n    """Test energy sensor reset service."""\n    config_entry = MockConfigEntry(\n        data={},\n        domain=DOMAIN,\n        options={\n            "cycle": "monthly",\n            "delta_values": False,\n            "name": "Energy bill",\n            "net_consumption": False,\n            "offset": 0,\n            "periodically_resetting": True,\n            "source": "sensor.energy",\n            "tariffs": ["peak", "offpeak"],\n        },\n        title="Energy bill",\n    )\n    config_entry.add_to_hass(hass)\n    assert await hass.config_entries.async_setup(config_entry.entry_id)\n    config_entry = MockConfigEntry(\n        data={},\n        domain=DOMAIN,\n        options={\n            "cycle": "monthly",\n            "delta_values": False,\n            "name": "Energy bill2",\n            "net_consumption": False,\n            "offset": 0,\n            "periodically_resetting": True,\n            "source": "sensor.energy",\n            "tariffs": ["peak", "offpeak"],\n        },\n        title="Energy bill2",\n    )\n    config_entry.add_to_hass(hass)\n    assert await hass.config_entries.async_setup(config_entry.entry_id)\n    await hass.async_block_till_done()\n\n    hass.bus.async_fire(EVENT_HOMEASSISTANT_START)\n    entity_id = "sensor.energy"\n    hass.states.async_set(\n        entity_id, 1, {ATTR_UNIT_OF_MEASUREMENT: UnitOfEnergy.KILO_WATT_HOUR}\n    )\n    await hass.async_block_till_done()\n\n    now = dt_util.utcnow() + timedelta(seconds=10)\n    with freeze_time(now):\n        hass.states.async_set(\n            entity_id,\n            3,\n            {ATTR_UNIT_OF_MEASUREMENT: UnitOfEnergy.KILO_WATT_HOUR},\n            force_update=True,\n        )\n        await hass.async_block_till_done()\n\n    state = hass.states.get("sensor.energy_bill_peak")\n    assert state.state == "2"\n\n    state = hass.states.get("sensor.energy_bill_offpeak")\n    assert state.state == "0"\n\n    # Change tariff\n    data = {ATTR_ENTITY_ID: "select.energy_bill", "option": "offpeak"}\n    await hass.services.async_call(SELECT_DOMAIN, SERVICE_SELECT_OPTION, data)\n    await hass.async_block_till_done()\n\n    now += timedelta(seconds=10)\n    with freeze_time(now):\n        hass.states.async_set(\n            entity_id,\n            4,\n            {ATTR_UNIT_OF_MEASUREMENT: UnitOfEnergy.KILO_WATT_HOUR},\n            force_update=True,\n        )\n        await hass.async_block_till_done()\n\n    state = hass.states.get("sensor.energy_bill_peak")\n    assert state.state == "2"\n\n    state = hass.states.get("sensor.energy_bill_offpeak")\n    assert state.state == "1"\n\n    # Change tariff\n    data = {ATTR_ENTITY_ID: "select.energy_bill", "option": "wrong_tariff"}\n    await hass.services.async_call(SELECT_DOMAIN, SERVICE_SELECT_OPTION, data)\n    await hass.async_block_till_done()\n\n    # Inexisting tariff, ignoring\n    assert hass.states.get("select.energy_bill").state != "wrong_tariff"\n\n    data = {ATTR_ENTITY_ID: "select.energy_bill", "option": "peak"}\n    await hass.services.async_call(SELECT_DOMAIN, SERVICE_SELECT_OPTION, data)\n    await hass.async_block_till_done()\n\n    now += timedelta(seconds=10)\n    with freeze_time(now):\n        hass.states.async_set(\n            entity_id,\n            5,\n            {ATTR_UNIT_OF_MEASUREMENT: UnitOfEnergy.KILO_WATT_HOUR},\n            force_update=True,\n        )\n        await hass.async_block_till_done()\n\n    state = hass.states.get("sensor.energy_bill_peak")\n    assert state.state == "3"\n\n    state = hass.states.get("sensor.energy_bill_offpeak")\n    assert state.state == "1"\n\n    # Reset meters\n    data = {ATTR_ENTITY_ID: "select.energy_bill"}\n    await hass.services.async_call(DOMAIN, SERVICE_RESET, data)\n    await hass.async_block_till_done()\n\n    state = hass.states.get("sensor.energy_bill_peak")\n    assert state.state == "0"\n\n    state = hass.states.get("sensor.energy_bill_offpeak")\n    assert state.state == "0"\n\n    # meanwhile energy_bill2_peak accumulated all kWh\n    state = hass.states.get("sensor.energy_bill2_peak")\n    assert state.state == "4"\n\n\nasync def test_cron(hass: HomeAssistant) -> None:\n    """Test cron pattern."""\n\n    config = {\n        "utility_meter": {\n            "energy_bill": {\n                "source": "sensor.energy",\n                "cron": "*/5 * * * *",\n            }\n        }\n    }\n\n    assert await async_setup_component(hass, DOMAIN, config)\n\n\nasync def test_cron_and_meter(hass: HomeAssistant) -> None:\n    """Test cron pattern and meter type fails."""\n    config = {\n        "utility_meter": {\n            "energy_bill": {\n                "source": "sensor.energy",\n                "cycle": "hourly",\n                "cron": "0 0 1 * *",\n            }\n        }\n    }\n\n    assert not await async_setup_component(hass, DOMAIN, config)\n\n\nasync def test_both_cron_and_meter(hass: HomeAssistant) -> None:\n    """Test cron pattern and meter type passes in different meter."""\n    config = {\n        "utility_meter": {\n            "energy_bill": {\n                "source": "sensor.energy",\n                "cron": "0 0 1 * *",\n            },\n            "water_bill": {\n                "source": "sensor.water",\n                "cycle": "hourly",\n            },\n        }\n    }\n\n    assert await async_setup_component(hass, DOMAIN, config)\n    await hass.async_block_till_done()\n\n\nasync def test_cron_and_offset(hass: HomeAssistant) -> None:\n    """Test cron pattern and offset fails."""\n\n    config = {\n        "utility_meter": {\n            "energy_bill": {\n                "source": "sensor.energy",\n                "offset": {"days": 1},\n                "cron": "0 0 1 * *",\n            }\n        }\n    }\n\n    assert not await async_setup_component(hass, DOMAIN, config)\n\n\nasync def test_bad_cron(hass: HomeAssistant) -> None:\n    """Test bad cron pattern."""\n\n    config = {\n        "utility_meter": {"energy_bill": {"source": "sensor.energy", "cron": "*"}}\n    }\n\n    assert not await async_setup_component(hass, DOMAIN, config)\n\n\nasync def test_setup_missing_discovery(hass: HomeAssistant) -> None:\n    """Test setup with configuration missing discovery_info."""\n    assert not await um_select.async_setup_platform(hass, {CONF_PLATFORM: DOMAIN}, None)\n    assert not await um_sensor.async_setup_platform(hass, {CONF_PLATFORM: DOMAIN}, None)\n\n\n@pytest.mark.parametrize(\n    ("tariffs", "expected_entities"),\n    [\n        (\n            [],\n            ["sensor.electricity_meter"],\n        ),\n        (\n            ["high", "low"],\n            [\n                "sensor.electricity_meter_low",\n                "sensor.electricity_meter_high",\n                "select.electricity_meter",\n            ],\n        ),\n    ],\n)\nasync def test_setup_and_remove_config_entry(\n    hass: HomeAssistant,\n    entity_registry: er.EntityRegistry,\n    tariffs: str,\n    expected_entities: list[str],\n) -> None:\n    """Test setting up and removing a config entry."""\n    input_sensor_entity_id = "sensor.input"\n\n    # Setup the config entry\n    config_entry = MockConfigEntry(\n        data={},\n        domain=DOMAIN,\n        options={\n            "cycle": "monthly",\n            "delta_values": False,\n            "name": "Electricity meter",\n            "net_consumption": False,\n            "offset": 0,\n            "periodically_resetting": True,\n            "source": input_sensor_entity_id,\n            "tariffs": tariffs,\n        },\n        title="Electricity meter",\n    )\n    config_entry.add_to_hass(hass)\n    assert await hass.config_entries.async_setup(config_entry.entry_id)\n    await hass.async_block_till_done()\n\n    assert len(hass.states.async_all()) == len(expected_entities)\n    assert len(entity_registry.entities) == len(expected_entities)\n    for entity in expected_entities:\n        assert hass.states.get(entity)\n        assert entity in entity_registry.entities\n\n    # Remove the config entry\n    assert await hass.config_entries.async_remove(config_entry.entry_id)\n    await hass.async_block_till_done()\n\n    # Check the state and entity registry entry are removed\n    assert len(hass.states.async_all()) == 0\n    assert len(entity_registry.entities) == 0\n',
        }
